# TIC Classifier - Temporal Invariance Compression
# Tests hypothesis: causal structure = invariant structure
# Success: >70% invariant/variant classification, >60% next-pulse prediction

param(
    [string]$LogDir = "logs",
    [string]$TestSet = "logs/test_set.md",
    [float]$Lambda = 0.7
)

$ErrorActionPreference = "Stop"

# --- INVARIANT PATTERNS ---
$InvariantPatterns = @(
    "Phase [0-9]",
    "COMPLETE|PENDING|Active",
    "Goals:|ARCHITECTURE|COMPRESSION-CAUSA",
    "\.md$",
    "^## ",
    "research/",
    "Last updated",
    "Breakaway is stateless"
)

# --- VARIANT PATTERNS ---
$VariantPatterns = @(
    "^[0-9]{4}-[0-9]{2}-[0-9]{2}",
    "pulse_[0-9]{4}-[0-9]{2}-[0-9]{2}",
    "\d{6}\.md",
    "Last pulse",
    "Observation|Action|Mutation",
    "No mutations applied"
)

function Get-LineType {
    param([string]$Line)

    $invScore = 0
    $varScore = 0

    foreach ($pat in $InvariantPatterns) {
        if ($Line -match $pat) { $invScore += 1 }
    }
    foreach ($pat in $VariantPatterns) {
        if ($Line -match $pat) { $varScore += 1 }
    }

    if ($invScore -gt $varScore) { return "INVARIANT" }
    if ($varScore -gt $invScore) { return "VARIANT" }
    return "NEUTRAL"
}

function Test-TICClassifier {
    Write-Host "=== TIC Classifier Test ===" -ForegroundColor Cyan
    Write-Host "Lambda threshold: $Lambda"
    Write-Host ""

    $logs = Get-ChildItem "logs/pulse_*.md" | Sort-Object LastWriteTime
    Write-Host "Found $($logs.Count) pulse logs"

    if ($logs.Count -lt 2) {
        Write-Host "ERROR: Need at least 2 pulse logs" -ForegroundColor Red
        return
    }

    # Analyze invariant ratio across logs
    $invariantCount = 0
    $totalLines = 0
    $invariantLines = @()

    foreach ($log in $logs) {
        $lines = Get-Content $log.FullName
        foreach ($line in $lines) {
            $totalLines++
            $type = Get-LineType $line
            if ($type -eq "INVARIANT") {
                $invariantCount++
                $invariantLines += $line
            }
        }
    }

    $invariantRatio = if ($totalLines -gt 0) { $invariantCount / $totalLines } else { 0 }

    Write-Host "Total lines analyzed: $totalLines"
    Write-Host "Classified as INVARIANT: $invariantCount ($([math]::Round($invariantRatio * 100, 1))%)"
    Write-Host ""

    # Predict next pulse from invariants
    Write-Host "=== Next Pulse Prediction ===" -ForegroundColor Cyan
    $uniqueInvariants = $invariantLines | Sort-Object -Unique
    Write-Host "Unique invariant lines for prediction: $($uniqueInvariants.Count)"

    # Test: Check if last log's invariants match prediction
    $lastLog = $logs[-1]
    $lastLines = Get-Content $lastLog.FullName
    $lastInvariants = $lastLines | Where-Object { (Get-LineType $_) -eq "INVARIANT" }

    $matchCount = 0
    foreach ($inv in $lastInvariants) {
        if ($uniqueInvariants -contains $inv) { $matchCount++ }
    }

    $predictionAccuracy = if ($lastInvariants.Count -gt 0) { $matchCount / $lastInvariants.Count } else { 0 }

