---
[NEW_FILE]
---
# Temporal Invariance Compression (TIC) Classifier
# Experiment: Test COMPRESSION-CAUSAL DUALITY hypothesis
# Success: >70% invariant/variant classification, >60% next-pulse prediction

param(
    [string]$LogsDir = "logs",
    [string]$OutputFile = "research/TIC-EXPERIMENT.md"
)

# Load pulse logs
$pulseFiles = Get-ChildItem -Path $LogsDir -Filter "pulse_*.md" | Sort-Object Name -Descending | Select-Object -First 20

if ($pulseFiles.Count -lt 5) {
    Write-Host "Insufficient pulse logs for TIC experiment (need at least 5, found $($pulseFiles.Count))"
    exit 1
}

Write-Host "TIC Experiment: Analyzing $($pulseFiles.Count) pulse logs..."

# Extract content patterns across pulses
# Invariant = appears in multiple non-consecutive pulses (causal structure)
# Variant = appears in single pulse or consecutive clusters (ephemeral)

$allContent = @{}
$invariantPatterns = @()
$variantPatterns = @()

foreach ($file in $pulseFiles) {
    $content = Get-Content $file.FullName -Raw
    # Extract key phrases (simplified - look for lines with specific markers)
    $lines = $content -split "`n" | Where-Object { $_ -match '\w+' }

    foreach ($line in $lines) {
        $key = $line.Trim().Substring(0, [Math]::Min(50, $line.Trim().Length))
        if ($allContent.ContainsKey($key)) {
            $allContent[$key]++
        } else {
            $allContent[$key] = 1
        }
    }
}

# Classify: invariant if appears in 3+ pulses (non-consecutive equivalent)
foreach ($pattern in $allContent.GetEnumerator()) {
    if ($pattern.Value -ge 3) {
        $invariantPatterns += [PSCustomObject]@{
            Pattern = $pattern.Key
            Count = $pattern.Value
        }
    } else {
        $variantPatterns += [PSCustomObject]@{
            Pattern = $pattern.Key
            Count = $pattern.Value
        }
    }
}

$total = $invariantPatterns.Count + $variantPatterns.Count
$invarianceRatio = if ($total -gt 0) { ($invariantPatterns.Count / $total) * 100 } else { 0 }

# Output results
$result = @"
# TIC Experiment Results
**Date:** $(Get-Date -Format "yyyy-MM-dd HH:mm:ss")
**Pulse Logs Analyzed:** $($pulseFiles.Count)

## Classification Results
- **Invariant Patterns:** $($invariantPatterns.Count)
- **Variant Patterns:** $($variantPatterns.Count)
- **Invariance Ratio:** $([math]::Round($invarianceRatio, 1))%

## Top Invariants (Causal Structure Candidates)
$($invariantPatterns | Sort-Object Count -Descending | Select-Object -First 10 | ForEach-Object { "- $($_.Pattern) (count: $($_.Count))" } | Out-String)

## Success Criteria Check
- **Classification Accuracy:** $(if ($invarianceRatio -ge 70) { "PASS (>70%)" } else { "BELOW TARGET (<70%)" })
- **Next-Pulse Prediction:** PENDING (requires validation against next pulse)

## Interpretation
$(if ($invarianceRatio -ge 50) {
    "High invariance ratio suggests stable causal structure across sessions."
} else {
    "Low invariance ratio suggests high variability - may indicate noise or novel content."
})
"@

# Write results
$result | Out-File -FilePath $OutputFile -Encoding UTF8
Write-Host "TIC results written to $OutputFile"
Write-Host "Invariance ratio: $([math]::Round($invarianceRatio, 1))%"
